from typing import List

class Solution:
    def getLongestSubsequence(self, words: List[str], groups: List[int]) -> List[str]:
        if not words or not groups:
            return []

        result = [words[0]]
        last_group = groups[0]

        for i in range(1, len(groups)):
            if groups[i] != last_group:
                result.append(words[i])
                last_group = groups[i]

        return result
```

This solution iterates through the `groups` array while keeping track of the last group added to the result. If the current group is different from the last added group, the corresponding word is added to the result. This ensures that the subsequence is alternating as required.
